using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, quantities, structures, and space." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language arts." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and civilizations." },
            new() { Id = 6, Code = "BIO", Name = "Biology", Description = "Study of living organisms and life processes." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Bio = "Dr. Chen specializes in distributed systems and cloud computing. She has published over 40 papers in top-tier conferences and holds several patents in fault-tolerant system design.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor", Bio = "Dr. Martinez focuses on artificial intelligence and machine learning. He previously worked at a leading AI research lab and brings industry experience to the classroom.", Email = "rmartinez@university.edu" },
            new() { Id = 3, Name = "Dr. Sarah Johnson", Title = "Professor", Bio = "Dr. Johnson is an expert in abstract algebra and number theory. She has received multiple teaching awards and authored two widely used textbooks.", Email = "sjohnson@university.edu" },
            new() { Id = 4, Name = "Dr. James Park", Title = "Assistant Professor", Bio = "Dr. Park researches quantum mechanics and particle physics. He completed his postdoctoral work at CERN and is passionate about making physics accessible.", Email = "jpark@university.edu" },
            new() { Id = 5, Name = "Dr. Emily White", Title = "Professor", Bio = "Dr. White is a literary scholar specializing in 19th-century American literature. She has published three books and serves on several editorial boards.", Email = "ewhite@university.edu" },
            new() { Id = 6, Name = "Dr. Michael Brown", Title = "Associate Professor", Bio = "Dr. Brown is a historian of the early modern period with a focus on transatlantic studies. He has received grants from the National Endowment for the Humanities.", Email = "mbrown@university.edu" },
            new() { Id = 7, Name = "Dr. Lisa Nguyen", Title = "Assistant Professor", Bio = "Dr. Nguyen studies molecular biology and genetics. Her lab investigates gene expression mechanisms in developmental biology.", Email = "lnguyen@university.edu" },
            new() { Id = 8, Name = "Dr. David Kim", Title = "Professor", Bio = "Dr. Kim is a statistician with expertise in Bayesian methods and applied probability. He consults regularly for government agencies on data analysis.", Email = "dkim@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "A broad introduction to computer science covering fundamental concepts including problem solving, algorithms, data representation, and an introduction to programming using Python.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Engineering Hall 201", MaxEnrollment = 120, CurrentEnrollment = 98, IsFeatured = true, DepartmentId = 1, InstructorId = 1 },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures & Algorithms", Description = "In-depth study of data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming, greedy algorithms). Includes complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Engineering Hall 305", MaxEnrollment = 60, CurrentEnrollment = 55, IsFeatured = true, DepartmentId = 1, InstructorId = 1 },
            new() { Id = 3, Code = "CS 420", Title = "Machine Learning", Description = "Foundations of machine learning including supervised and unsupervised learning, neural networks, and model evaluation. Students complete a capstone project applying ML to a real-world dataset.", Credits = 4, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Engineering Hall 110", MaxEnrollment = 45, CurrentEnrollment = 44, IsFeatured = true, DepartmentId = 1, InstructorId = 2 },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to systems of equations. Essential for students in mathematics, physics, engineering, and computer science.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Science Center 102", MaxEnrollment = 80, CurrentEnrollment = 62, IsFeatured = false, DepartmentId = 2, InstructorId = 3 },
            new() { Id = 5, Code = "MATH 310", Title = "Probability & Statistics", Description = "Introduction to probability theory, random variables, distributions, hypothesis testing, and regression analysis. Emphasizes both theory and practical data interpretation.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Science Center 205", MaxEnrollment = 70, CurrentEnrollment = 48, IsFeatured = false, DepartmentId = 2, InstructorId = 8 },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Covers Newton's laws, energy, momentum, rotational motion, and an introduction to thermodynamic principles. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM + Thu Lab 2:00–4:50 PM", Location = "Physics Building 101", MaxEnrollment = 90, CurrentEnrollment = 73, IsFeatured = true, DepartmentId = 3, InstructorId = 4 },
            new() { Id = 7, Code = "PHYS 320", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, the Schrödinger equation, angular momentum, and spin. Prerequisites: PHYS 101, MATH 201.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Physics Building 210", MaxEnrollment = 35, CurrentEnrollment = 28, IsFeatured = false, DepartmentId = 3, InstructorId = 4 },
            new() { Id = 8, Code = "ENG 110", Title = "College Writing", Description = "Develops skills in academic writing including argumentation, research methods, and critical reading. Students write multiple essays across different genres and rhetorical situations.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", Location = "Humanities Building 305", MaxEnrollment = 25, CurrentEnrollment = 22, IsFeatured = false, DepartmentId = 4, InstructorId = 5 },
            new() { Id = 9, Code = "ENG 350", Title = "American Literature", Description = "Survey of major works of American literature from the colonial period through the present. Themes include identity, democracy, and the American experience.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", Location = "Humanities Building 210", MaxEnrollment = 30, CurrentEnrollment = 18, IsFeatured = false, DepartmentId = 4, InstructorId = 5 },
            new() { Id = 10, Code = "HIST 200", Title = "World History to 1500", Description = "Survey of world civilizations from antiquity through the late medieval period. Covers major empires, trade networks, religious movements, and cultural exchanges.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Humanities Building 120", MaxEnrollment = 100, CurrentEnrollment = 67, IsFeatured = false, DepartmentId = 5, InstructorId = 6 },
            new() { Id = 11, Code = "HIST 340", Title = "The Atlantic World", Description = "Explores the interconnected histories of Europe, Africa, and the Americas from the 15th through 19th centuries. Topics include colonialism, slavery, revolution, and cultural exchange.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", Location = "Humanities Building 315", MaxEnrollment = 40, CurrentEnrollment = 25, IsFeatured = false, DepartmentId = 5, InstructorId = 6 },
            new() { Id = 12, Code = "BIO 101", Title = "Introduction to Biology", Description = "Fundamental principles of biology including cell structure, genetics, evolution, and ecology. Includes laboratory component with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed 8:00–9:20 AM + Fri Lab 1:00–3:50 PM", Location = "Life Sciences 101", MaxEnrollment = 100, CurrentEnrollment = 85, IsFeatured = true, DepartmentId = 6, InstructorId = 7 },
            new() { Id = 13, Code = "BIO 310", Title = "Molecular Biology", Description = "Structure and function of biological macromolecules, DNA replication, transcription, translation, and gene regulation. Prerequisites: BIO 101.", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM", Location = "Life Sciences 220", MaxEnrollment = 40, CurrentEnrollment = 32, IsFeatured = false, DepartmentId = 6, InstructorId = 7 },
            new() { Id = 14, Code = "CS 210", Title = "Software Engineering", Description = "Principles of software development including requirements analysis, design patterns, version control, testing, and agile methodologies. Team-based project throughout the semester.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", Location = "Engineering Hall 202", MaxEnrollment = 50, CurrentEnrollment = 42, IsFeatured = false, DepartmentId = 1, InstructorId = 2 },
            new() { Id = 15, Code = "MATH 410", Title = "Abstract Algebra", Description = "Groups, rings, fields, and their homomorphisms. Topics include Lagrange's theorem, quotient groups, polynomial rings, and field extensions.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", Location = "Science Center 310", MaxEnrollment = 30, CurrentEnrollment = 19, IsFeatured = false, DepartmentId = 2, InstructorId = 3 },
        };

        // Wire up navigation properties
        foreach (var course in _courses)
        {
            course.Department = _departments.First(d => d.Id == course.DepartmentId);
            course.Instructor = _instructors.First(i => i.Id == course.InstructorId);
        }
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

