@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService Catalog
@inject NavigationManager Navigation

<PageTitle>Browse Courses — University Course Catalog</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input id="search" type="text" class="form-control" placeholder="Search by title, code, or keyword…"
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select id="department" class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

@if (filteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th>Enrollment</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in filteredCourses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Department?.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td>
                        @course.CurrentEnrollment / @course.MaxEnrollment
                        @if (course.CurrentEnrollment >= course.MaxEnrollment)
                        {
                            <span class="badge bg-danger ms-1">Full</span>
                        }
                    </td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    private string _searchTerm = string.Empty;
    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; ApplyFilters(); }
    }

    private int _selectedDepartmentId;
    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; ApplyFilters(); }
    }

    [SupplyParameterFromQuery] public int? departmentId { get; set; }

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        if (departmentId.HasValue)
            _selectedDepartmentId = departmentId.Value;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        int? deptFilter = _selectedDepartmentId > 0 ? _selectedDepartmentId : null;
        filteredCourses = Catalog.GetCourses(_searchTerm, deptFilter);
    }

    private void ClearFilters()
    {
        _searchTerm = string.Empty;
        _selectedDepartmentId = 0;
        ApplyFilters();
    }
}

