@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog
@inject NavigationManager Navigation

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Complete the form below to submit your enrollment request. You will receive confirmation from the registrar's office.</p>

<div class="row">
    <div class="col-md-8 col-lg-6">
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger mb-3" />

            <div class="mb-3">
                <label for="fullName" class="form-label">Full Name</label>
                <InputText id="fullName" class="form-control" @bind-Value="model.FullName" />
                <ValidationMessage For="() => model.FullName" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" placeholder="e.g. STU123456" />
                <ValidationMessage For="() => model.StudentId" />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                    <option value="0">— Select a course —</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        </EditForm>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? courseId { get; set; }

    private List<Course> courses = new();

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();
        if (courseId.HasValue && model.CourseId == 0)
            model.CourseId = courseId.Value;
    }

    private void HandleSubmit()
    {
        Catalog.SubmitEnrollment(model);
        Navigation.NavigateTo($"/enroll/confirmation?course={model.CourseId}&name={Uri.EscapeDataString(model.FullName)}");
    }
}

