@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found") — University Course Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-outline-primary">← Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@course.DepartmentId">@course.Department?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><strong>Course Description</strong></div>
                <div class="card-body">
                    <p>@course.Description</p>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header"><strong>Instructor</strong></div>
                <div class="card-body">
                    <h5>@course.Instructor?.Name</h5>
                    <p class="text-muted mb-1">@course.Instructor?.Title</p>
                    <p>@course.Instructor?.Bio</p>
                    <p><strong>Contact:</strong> <a href="mailto:@course.Instructor?.Email">@course.Instructor?.Email</a></p>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>Details</strong></div>
                <ul class="list-group list-group-flush">
                    <li class="list-group-item"><strong>Credits:</strong> @course.Credits</li>
                    <li class="list-group-item"><strong>Schedule:</strong> @course.Schedule</li>
                    <li class="list-group-item"><strong>Location:</strong> @course.Location</li>
                    <li class="list-group-item"><strong>Department:</strong> @course.Department?.Name</li>
                    <li class="list-group-item">
                        <strong>Enrollment:</strong> @course.CurrentEnrollment / @course.MaxEnrollment
                        @if (course.CurrentEnrollment >= course.MaxEnrollment)
                        {
                            <span class="badge bg-danger ms-1">Full</span>
                        }
                        else
                        {
                            <span class="badge bg-success ms-1">Open</span>
                        }
                    </li>
                </ul>
            </div>

            <a href="enroll?courseId=@course.Id" class="btn btn-primary w-100">Request Enrollment</a>
            <a href="courses" class="btn btn-outline-secondary w-100 mt-2">← Back to Courses</a>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}
