@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found") — University Course Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-outline-primary">← Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@course.DepartmentId">@course.Department?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><strong>Course Description</strong></div>
                <div class="card-body">
                    <p>@course.Description</p>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header"><strong>Instructor</strong></div>
                <div class="card-body">
                    <h5>@course.Instructor?.Name</h5>
                    <p class="text-muted mb-1">@course.Instructor?.Title</p>
                    <p>@course.Instructor?.Bio</p>
                    <p><strong>Contact:</strong> <a href="mailto:@course.Instructor?.Email">@course.Instructor?.Email</a></p>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>Details</strong></div>
                <ul class="list-group list-group-flush">
                    <li class="list-group-item"><strong>Credits:</strong> @course.Credits</li>
                    <li class="list-group-item"><strong>Schedule:</strong> @course.Schedule</li>
                    <li class="list-group-item"><strong>Location:</strong> @course.Location</li>
                    <li class="list-group-item"><strong>Department:</strong> @course.Department?.Name</li>
                    <li class="list-group-item">
                        <strong>Enrollment:</strong> @course.CurrentEnrollment / @course.MaxEnrollment
                        @if (course.CurrentEnrollment >= course.MaxEnrollment)
                        {
                            <span class="badge bg-danger ms-1">Full</span>
                        }
                        else
                        {
                            <span class="badge bg-success ms-1">Open</span>
                        }
                    </li>
                </ul>
            </div>

            <a href="enroll?courseId=@course.Id" class="btn btn-primary w-100">Request Enrollment</a>
            <a href="courses" class="btn btn-outline-secondary w-100 mt-2">← Back to Courses</a>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog
@inject NavigationManager Navigation

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Complete the form below to submit your enrollment request. You will receive confirmation from the registrar's office.</p>

<div class="row">
    <div class="col-md-8 col-lg-6">
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger mb-3" />

            <div class="mb-3">
                <label for="fullName" class="form-label">Full Name</label>
                <InputText id="fullName" class="form-control" @bind-Value="model.FullName" />
                <ValidationMessage For="() => model.FullName" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" placeholder="e.g. STU123456" />
                <ValidationMessage For="() => model.StudentId" />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                    <option value="0">— Select a course —</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        </EditForm>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? courseId { get; set; }

    private List<Course> courses = new();

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();
        if (courseId.HasValue && model.CourseId == 0)
            model.CourseId = courseId.Value;
    }

    private void HandleSubmit()
    {
        Catalog.SubmitEnrollment(model);
        Navigation.NavigateTo($"/enroll/confirmation?course={model.CourseId}&name={Uri.EscapeDataString(model.FullName)}");
    }
}

@page "/enroll/confirmation"
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Submitted — University Course Catalog</PageTitle>

<div class="text-center mt-5">
    <h1 class="text-success">✅ Enrollment Request Submitted</h1>

    @if (course is not null)
    {
        <p class="lead mt-3">
            Thank you, <strong>@name</strong>! Your enrollment request for
            <strong>@course.Code — @course.Title</strong> has been received.
        </p>
    }
    else
    {
        <p class="lead mt-3">Your enrollment request has been received.</p>
    }

    <p class="text-muted">The registrar's office will process your request and send confirmation to your university email.</p>

    <div class="mt-4">
        <a href="courses" class="btn btn-outline-primary me-2">Browse More Courses</a>
        <a href="enroll" class="btn btn-primary">Submit Another Request</a>
    </div>
</div>

@code {
    [SupplyParameterFromQuery] public int? course_id { get; set; }
    [SupplyParameterFromQuery(Name = "course")] public int? courseId { get; set; }
    [SupplyParameterFromQuery] public string? name { get; set; }

    private UniversityCourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        var id = courseId ?? course_id;
        if (id.HasValue)
            course = Catalog.GetCourse(id.Value);
    }
}

